  1→/**
  2→ * Phase execution engine for workflow orchestration.
  3→ *
  4→ * Handles executing individual phases via an AgentDriver interface,
  5→ * including cold-start retry logic and MCP fallback strategies.
  6→ *
  7→ * The SDK import has been moved to ClaudeCodeDriver — this module
  8→ * is agent-agnostic.
  9→ */
 10→
 11→import chalk from "chalk";
 12→import { ShutdownManager } from "../shutdown.js";
 13→import { PhaseSpinner } from "../phase-spinner.js";
 14→import { Phase, ExecutionConfig, PhaseResult, QaVerdict } from "./types.js";
 15→import { readAgentsMd } from "../agents-md.js";
 16→import { getDriver } from "./drivers/index.js";
 17→import type { AgentDriver, AgentExecutionConfig } from "./drivers/index.js";
 18→
 19→/**
 20→ * Natural language prompts for each phase
 21→ * These prompts will invoke the corresponding skills via natural language
 22→ */
 23→const PHASE_PROMPTS: Record<Phase, string> = {
 24→  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
 25→  "security-review":
 26→    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
 27→  testgen:
 28→    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
 29→  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
 30→  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
 31→  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
 32→  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
 33→};
 34→
 35→/**
 36→ * Phases that require worktree isolation.
 37→ * Only `spec` runs in the main repo (planning-only, no file changes).
 38→ * All other phases must run in the worktree because:
 39→ * 1. They need to read/modify the worktree code
 40→ * 2. Resuming a session created in a different cwd crashes the SDK
 41→ */
 42→const ISOLATED_PHASES: Phase[] = [
 43→  "exec",
 44→  "security-review",
 45→  "testgen",
 46→  "test",
 47→  "qa",
 48→  "loop",
 49→];
 50→
 51→/**
 52→ * Cold-start retry threshold in seconds.
 53→ * Failures under this duration are likely Claude Code subprocess initialization
 54→ * issues rather than genuine phase failures (based on empirical data: cold-start
 55→ * failures consistently complete in 15-39s vs 150-310s for real work).
 56→ */
 57→const COLD_START_THRESHOLD_SECONDS = 60;
 58→const COLD_START_MAX_RETRIES = 2;
 59→
 60→export function parseQaVerdict(output: string): QaVerdict | null {
 61→  if (!output) return null;
 62→
 63→  // Match various verdict formats:
 64→  // - "### Verdict: X" (markdown header)
 65→  // - "**Verdict:** X" (bold label with colon inside)
 66→  // - "**Verdict:** **X**" (bold label and bold value)
 67→  // - "Verdict: X" (plain)
 68→  // Case insensitive, handles optional markdown formatting
 69→  const verdictMatch = output.match(
 70→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
 71→  );
 72→
 73→  if (!verdictMatch) return null;
 74→
 75→  // Normalize to uppercase with underscores
 76→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
 77→  return verdict;
 78→}
 79→
 80→/**
 81→ * Format duration in human-readable format
 82→ */
 83→export function formatDuration(seconds: number): string {
 84→  if (seconds < 60) {
 85→    return `${seconds.toFixed(1)}s`;
 86→  }
 87→  const mins = Math.floor(seconds / 60);
 88→  const secs = seconds % 60;
 89→  return `${mins}m ${secs.toFixed(0)}s`;
 90→}
 91→
 92→/**
 93→ * Get the prompt for a phase with the issue number substituted.
 94→ * Includes AGENTS.md content as context so non-Claude agents
 95→ * receive project conventions and workflow instructions.
 96→ */
 97→async function getPhasePrompt(
 98→  phase: Phase,
 99→  issueNumber: number,
100→): Promise<string> {
101→  const basePrompt = PHASE_PROMPTS[phase].replace(
102→    /\{issue\}/g,
103→    String(issueNumber),
104→  );
105→
106→  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
107→  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
108→  // rely on AGENTS.md for project context.
109→  const agentsMd = await readAgentsMd();
110→  if (agentsMd) {
111→    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
112→  }
113→
114→  return basePrompt;
115→}
116→
117→/**
118→ * Execute a single phase for an issue using the configured AgentDriver.
119→ */
120→async function executePhase(
121→  issueNumber: number,
122→  phase: Phase,
123→  config: ExecutionConfig,
124→  sessionId?: string,
125→  worktreePath?: string,
126→  shutdownManager?: ShutdownManager,
127→  spinner?: PhaseSpinner,
128→): Promise<PhaseResult & { sessionId?: string }> {
129→  const startTime = Date.now();
130→
131→  if (config.dryRun) {
132→    // Dry run - just simulate
133→    if (config.verbose) {
134→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
135→    }
136→    return {
137→      phase,
138→      success: true,
139→      durationSeconds: 0,
140→    };
141→  }
142→
143→  const prompt = await getPhasePrompt(phase, issueNumber);
144→
145→  if (config.verbose) {
146→    console.log(chalk.gray(`    Prompt: ${prompt}`));
147→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
148→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
149→    }
150→  }
151→
152→  // Determine working directory and environment
153→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
154→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
155→
156→  // Check if shutdown is in progress
157→  if (shutdownManager?.shuttingDown) {
158→    return {
159→      phase,
160→      success: false,
161→      durationSeconds: 0,
162→      error: "Shutdown in progress",
163→    };
164→  }
165→
166→  // Create abort controller for timeout
167→  const abortController = new AbortController();
168→  const timeoutId = setTimeout(() => {
169→    abortController.abort();
170→  }, config.phaseTimeout * 1000);
171→
172→  // Register abort controller with shutdown manager for graceful shutdown
173→  if (shutdownManager) {
174→    shutdownManager.setAbortController(abortController);
175→  }
176→
177→  // Build environment with worktree isolation variables
178→  const env: Record<string, string> = {
179→    ...process.env,
180→    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
181→  };
182→
183→  // Set worktree isolation environment variables
184→  if (shouldUseWorktree) {
185→    env.SEQUANT_WORKTREE = worktreePath;
186→    env.SEQUANT_ISSUE = String(issueNumber);
187→  }
188→
189→  // Set orchestration context for skills to detect they're part of a workflow
190→  // Skills can check these to skip redundant pre-flight checks
191→  env.SEQUANT_ORCHESTRATOR = "sequant-run";
192→  env.SEQUANT_PHASE = phase;
193→
194→  // Track whether we're actively streaming verbose output
195→  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
196→  // (Issue #283: ora's stop() clears the current line, which can truncate output when
197→  // pause/resume is called for every chunk in rapid succession)
198→  let verboseStreamingActive = false;
199→
200→  // Safety: never resume a session when worktree isolation is active.
201→  // Even if THIS phase doesn't use the worktree, a previous phase may have
202→  // created the session there. Resuming from a different cwd crashes the SDK
203→  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
204→  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
205→  const canResume = sessionId && !worktreePath;
206→
207→  // Build AgentExecutionConfig for the driver
208→  const agentConfig: AgentExecutionConfig = {
209→    cwd,
210→    env,
211→    abortSignal: abortController.signal,
212→    phaseTimeout: config.phaseTimeout,
213→    verbose: config.verbose,
214→    mcp: config.mcp,
215→    sessionId: canResume ? sessionId : undefined,
216→    onOutput: config.verbose
217→      ? (text: string) => {
218→          if (!verboseStreamingActive) {
219→            spinner?.pause();
220→            verboseStreamingActive = true;
221→          }
222→          process.stdout.write(chalk.gray(text));
223→        }
224→      : undefined,
225→    onStderr: config.verbose
226→      ? (data: string) => {
227→          if (!verboseStreamingActive) {
228→            spinner?.pause();
229→            verboseStreamingActive = true;
230→          }
231→          process.stderr.write(chalk.red(data));
232→        }
233→      : undefined,
234→  };
235→
236→  // Resolve driver from config or default
237→  const driver: AgentDriver = getDriver(config.agent);
238→
239→  const agentResult = await driver.executePhase(prompt, agentConfig);
240→
241→  // Resume spinner after execution completes (if we paused it)
242→  if (verboseStreamingActive) {
243→    spinner?.resume();
244→  }
245→
246→  clearTimeout(timeoutId);
247→
248→  // Clear abort controller from shutdown manager
249→  if (shutdownManager) {
250→    shutdownManager.clearAbortController();
251→  }
252→
253→  const durationSeconds = (Date.now() - startTime) / 1000;
254→
255→  // Map AgentPhaseResult to PhaseResult
256→  if (agentResult.success) {
257→    // For QA phase, check the verdict to determine actual success
258→    // Agent "success" just means the execution completed — we need to parse the verdict
259→    if (phase === "qa" && agentResult.output) {
260→      const verdict = parseQaVerdict(agentResult.output);
261→      if (
262→        verdict &&
263→        verdict !== "READY_FOR_MERGE" &&
264→        verdict !== "NEEDS_VERIFICATION"
265→      ) {
266→        return {
267→          phase,
268→          success: false,
269→          durationSeconds,
270→          error: `QA verdict: ${verdict}`,
271→          sessionId: agentResult.sessionId,
272→          output: agentResult.output,
273→          verdict,
274→        };
275→      }
276→      return {
277→        phase,
278→        success: true,
279→        durationSeconds,
280→        sessionId: agentResult.sessionId,
281→        output: agentResult.output,
282→        verdict: verdict ?? undefined,
283→      };
284→    }
285→
286→    return {
287→      phase,
288→      success: true,
289→      durationSeconds,
290→      sessionId: agentResult.sessionId,
291→      output: agentResult.output,
292→    };
293→  }
294→
295→  return {
296→    phase,
297→    success: false,
298→    durationSeconds,
299→    error: agentResult.error,
300→    sessionId: agentResult.sessionId,
301→  };
302→}
303→
304→/**
305→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
306→ *
307→ * Retry strategy:
308→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
309→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
310→ *    can fail on first run due to cold-cache issues)
311→ *
312→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
313→ * for core functionality.
314→ */
315→/**
316→ * @internal Exported for testing only
317→ */
318→export async function executePhaseWithRetry(
319→  issueNumber: number,
320→  phase: Phase,
321→  config: ExecutionConfig,
322→  sessionId?: string,
323→  worktreePath?: string,
324→  shutdownManager?: ShutdownManager,
325→  spinner?: PhaseSpinner,
326→  /** @internal Injected for testing — defaults to module-level executePhase */
327→  executePhaseFn: typeof executePhase = executePhase,
328→): Promise<PhaseResult & { sessionId?: string }> {
329→  // Skip retry logic if explicitly disabled
330→  if (config.retry === false) {
331→    return executePhaseFn(
332→      issueNumber,
333→      phase,
334→      config,
335→      sessionId,
336→      worktreePath,
337→      shutdownManager,
338→      spinner,
339→    );
340→  }
341→
342→  let lastResult: PhaseResult & { sessionId?: string };
343→
344→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
345→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
346→    lastResult = await executePhaseFn(
347→      issueNumber,
348→      phase,
349→      config,
350→      sessionId,
351→      worktreePath,
352→      shutdownManager,
353→      spinner,
354→    );
355→
356→    const duration = lastResult.durationSeconds ?? 0;
357→
358→    // Success or genuine failure (took long enough to be real work)
359→    if (lastResult.success || duration >= COLD_START_THRESHOLD_SECONDS) {
360→      return lastResult;
361→    }
362→
363→    // Cold-start failure detected — retry
364→    if (attempt < COLD_START_MAX_RETRIES) {
365→      if (config.verbose) {
366→        console.log(
367→          chalk.yellow(
368→            `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
369→          ),
370→        );
371→      }
372→    }
373→  }
374→
375→  // Capture the original error for better diagnostics
376→  const originalError = lastResult!.error;
377→
378→  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
379→  // This handles npx-based MCP servers that fail on first run due to cold-cache issues
380→  if (config.mcp && !lastResult!.success) {
381→    console.log(
382→      chalk.yellow(
383→        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
384→      ),
385→    );
386→
387→    // Create config copy with MCP disabled
388→    const configWithoutMcp: ExecutionConfig = {
389→      ...config,
390→      mcp: false,
391→    };
392→
393→    const retryResult = await executePhaseFn(
394→      issueNumber,
395→      phase,
396→      configWithoutMcp,
397→      sessionId,
398→      worktreePath,
399→      shutdownManager,
400→      spinner,
401→    );
402→
403→    if (retryResult.success) {
404→      console.log(
405→        chalk.green(
406→          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
407→        ),
408→      );
409→      return retryResult;
410→    }
411→
412→    // Both attempts failed - return original error for better diagnostics
413→    return {
414→      ...lastResult!,
415→      error: originalError,
416→    };
417→  }
418→
419→  return lastResult!;
420→}
