 45→ * (case-insensitive matching)
 46→ */
 47→const SKIP_ISSUE_LABELS = [
 48→  "wontfix",
 49→  "won't fix",
 50→  "duplicate",
 51→  "invalid",
 52→  "question",
 53→  "documentation",
 54→  "docs",
 55→];
