/**
 * sequant doctor - Check installation health
 */

import chalk from "chalk";
import { execSync } from "child_process";
import { ui, colors } from "../lib/cli-ui.js";
import { GitHubProvider } from "../lib/workflow/platforms/github.js";
import { fileExists, isExecutable } from "../lib/fs.js";
import { getManifest } from "../lib/manifest.js";
import {
  commandExists,
  isGhAuthenticated,
  isNativeWindows,
  isWSL,
  checkOptionalMcpServers,
  getMcpServersConfig,
  OPTIONAL_MCP_SERVERS,
} from "../lib/system.js";
import {
  checkVersionThorough,
  getVersionWarning,
} from "../lib/version-check.js";
import { areSkillsOutdated } from "./sync.js";
import {
  readAgentsMd,
  checkAgentsMdConsistency,
  AGENTS_MD_PATH,
} from "../lib/agents-md.js";
import { readFile } from "../lib/fs.js";

interface Check {
  name: string;
  status: "pass" | "warn" | "fail";
  message: string;
  fix?: () => Promise<void>;
}

export interface DoctorOptions {
  skipIssueCheck?: boolean;
}

/**
 * Labels that indicate an issue should be skipped from closed-issue verification
 * (case-insensitive matching)
 */
const SKIP_ISSUE_LABELS = [
  "wontfix",
  "won't fix",
  "duplicate",
  "invalid",
  "question",
  "documentation",
  "docs",
];

interface ClosedIssue {
  number: number;
  title: string;
  closedAt: string;
  labels: Array<{ name: string }>;
}

/**
 * Check recently closed issues for missing commits in main branch
 * Returns issues that were closed but have no commit referencing them
 */
export function checkClosedIssues(): ClosedIssue[] {
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
  const sevenDaysAgoISO = sevenDaysAgo.toISOString();

  // Fetch closed issues from last 7 days
  const github = new GitHubProvider();
  const closedIssues = github.listClosedIssuesSync(100) as ClosedIssue[];

  // Filter to last 7 days
  const recentIssues = closedIssues.filter(
    (issue) => issue.closedAt >= sevenDaysAgoISO,
  );

  // Filter out issues with skip labels
  const issuesToCheck = recentIssues.filter((issue) => {
    const labels = issue.labels.map((l) => l.name.toLowerCase());
    return !SKIP_ISSUE_LABELS.some((skipLabel) =>
      labels.some((label) => label.includes(skipLabel.toLowerCase())),
    );
  });

  // Check each issue for a commit in main
  const missingCommitIssues: ClosedIssue[] = [];
  for (const issue of issuesToCheck) {
    try {
      // Look for commit mentioning this issue number
      const result = execSync(
        `git log --oneline --grep="#${issue.number}" -1`,
        {
          encoding: "utf-8",
          stdio: ["pipe", "pipe", "pipe"],
        },
      );
      // If no output, no commit found
      if (!result.trim()) {
        missingCommitIssues.push(issue);
      }
    } catch {
      // git log failed or no match - treat as missing
      missingCommitIssues.push(issue);
    }
  }

  return missingCommitIssues;
}

export async function doctorCommand(
  options: DoctorOptions = {},
): Promise<void> {
  console.log(ui.headerBox("SEQUANT HEALTH CHECK"));
  console.log();

  const checks: Check[] = [];
  // Track gh availability and auth for conditional checks later
  let ghAvailable = false;
  let ghAuthenticated = false;

  // Check 0: Version freshness
  const versionResult = await checkVersionThorough();
  if (versionResult.latestVersion) {
    if (versionResult.isOutdated) {
      checks.push({
        name: "Version",
        status: "warn",
        message: `Outdated: ${versionResult.currentVersion} → ${versionResult.latestVersion} available`,
      });
      // Show remediation steps
      console.log(
        chalk.yellow(
          `  ⚠️  ${getVersionWarning(versionResult.currentVersion, versionResult.latestVersion, versionResult.isLocalInstall)}`,
        ),
      );
      console.log("");
    } else {
      checks.push({
        name: "Version",
        status: "pass",
        message: `Up to date (${versionResult.currentVersion})`,
      });
    }
  } else {
    // Could not fetch version - skip this check silently (graceful degradation)
    checks.push({
      name: "Version",
      status: "pass",
      message: `${versionResult.currentVersion} (could not verify latest)`,
    });
  }

  // Check 1: Manifest exists
  const manifest = await getManifest();
  if (manifest) {
    checks.push({
      name: "Manifest",
      status: "pass",
      message: `Found .sequant-manifest.json (v${manifest.version})`,
    });
  } else {
    checks.push({
      name: "Manifest",
      status: "fail",
      message: "Missing .sequant-manifest.json - run `sequant init`",
    });
  }

  // Check 2: Skills directory
  const skillsExist = await fileExists(".claude/skills");
  if (skillsExist) {
    checks.push({
      name: "Skills",
      status: "pass",
      message: "Skills directory exists",
    });
  } else {
    checks.push({
      name: "Skills",
      status: "fail",
      message: "Missing .claude/skills/ directory",
    });
  }

  // Check 3: Core skills present
  const coreSkills = ["spec", "exec", "qa"];
  const missingSkills: string[] = [];
  for (const skill of coreSkills) {
    if (!(await fileExists(`.claude/skills/${skill}/SKILL.md`))) {
      missingSkills.push(skill);
    }
  }
  if (missingSkills.length === 0) {
    checks.push({
      name: "Core Skills",
      status: "pass",
      message: "All core skills present (spec, exec, qa)",
    });
  } else {
    checks.push({
      name: "Core Skills",
      status: "fail",
      message: `Missing skills: ${missingSkills.join(", ")}`,
    });
  }

  // Check 3.5: Skills version (are skills in sync with package?)
  const skillsStatus = await areSkillsOutdated();
  if (skillsStatus.outdated) {
    checks.push({
      name: "Skills Version",
      status: "warn",
      message: `Outdated (${skillsStatus.currentVersion || "unknown"} → ${skillsStatus.packageVersion}) - run: npx sequant sync`,
    });
  } else {
    checks.push({
      name: "Skills Version",
      status: "pass",
      message: `Up to date (${skillsStatus.packageVersion})`,
    });
  }

  // Check: AGENTS.md presence and consistency
  const agentsMdContent = await readAgentsMd();
  if (agentsMdContent) {
    // Check consistency with CLAUDE.md if both exist
    if (await fileExists("CLAUDE.md")) {
      try {
        const claudeMdContent = await readFile("CLAUDE.md");
        const inconsistency = checkAgentsMdConsistency(
          agentsMdContent,
          claudeMdContent,
        );
        if (inconsistency) {
          checks.push({
            name: "AGENTS.md",
            status: "warn",
            message: `Out of sync with CLAUDE.md: ${inconsistency}. Run: sequant sync --force`,
          });
        } else {
          checks.push({
            name: "AGENTS.md",
            status: "pass",
            message: "Present and consistent with CLAUDE.md",
          });
        }
      } catch {
        checks.push({
          name: "AGENTS.md",
          status: "pass",
          message: "Present (could not verify consistency)",
        });
      }
    } else {
      checks.push({
        name: "AGENTS.md",
        status: "pass",
        message: "Present",
      });
    }
  } else if (manifest) {
    checks.push({
      name: "AGENTS.md",
      status: "warn",
      message: `Missing ${AGENTS_MD_PATH} - run: sequant init --force (or sequant sync --force)`,
    });
  }

  // Check 4: Hooks directory
  const hooksExist = await fileExists(".claude/hooks");
  if (hooksExist) {
    checks.push({
      name: "Hooks",
      status: "pass",
      message: "Hooks directory exists",
    });
  } else {
    checks.push({
      name: "Hooks",
      status: "warn",
      message: "No hooks directory (optional but recommended)",
    });
  }

  // Check 5: Hook scripts executable
  const preToolHook = ".claude/hooks/pre-tool.sh";
  if (await fileExists(preToolHook)) {
    if (await isExecutable(preToolHook)) {
      checks.push({
        name: "Hook Permissions",
        status: "pass",
        message: "Hook scripts are executable",
      });
    } else {
      checks.push({
        name: "Hook Permissions",
        status: "warn",
        message:
          "Hook scripts not executable - run: chmod +x .claude/hooks/*.sh",
      });
    }
  }

  // Check 6: Settings.json
  const settingsExist = await fileExists(".claude/settings.json");
  if (settingsExist) {
    checks.push({
      name: "Settings",
      status: "pass",
      message: "Settings file exists",
    });
  } else {
    checks.push({
      name: "Settings",
      status: "warn",
      message: "No settings.json (hooks won't be triggered)",
    });
  }

  // Check 7: Git repo
  const gitExists = await fileExists(".git");
  if (gitExists) {
    checks.push({
      name: "Git Repository",
      status: "pass",
      message: "Git repository detected",
    });
  } else {
    checks.push({
      name: "Git Repository",
      status: "warn",
      message: "Not a git repository (worktree features won't work)",
    });
  }

  // Check 8: GitHub CLI installed
  if (commandExists("gh")) {
    ghAvailable = true;
    checks.push({
      name: "GitHub CLI",
      status: "pass",
      message: "gh CLI is installed",
    });

    // Check 9: GitHub CLI authenticated (only if gh exists)
    if (isGhAuthenticated()) {
      ghAuthenticated = true;
      checks.push({
        name: "GitHub Auth",
        status: "pass",
        message: "gh CLI is authenticated",
      });
    } else {
      checks.push({
        name: "GitHub Auth",
        status: "fail",
        message: "gh CLI not authenticated - run: gh auth login",
      });
    }
  } else {
    checks.push({
      name: "GitHub CLI",
      status: "fail",
      message: "gh CLI not installed - see: https://cli.github.com",
    });
  }

  // Check 10: Claude Code CLI installed (critical)
  if (commandExists("claude")) {
    checks.push({
      name: "Claude Code CLI",
      status: "pass",
      message: "claude CLI is installed",
    });
  } else {
    checks.push({
      name: "Claude Code CLI",
      status: "fail",
      message:
        "claude CLI not installed - see: https://docs.anthropic.com/en/docs/claude-code",
    });
  }

  // Check 12: jq installed (optional but recommended)
  if (commandExists("jq")) {
    checks.push({
      name: "jq",
      status: "pass",
      message: "jq is installed (faster JSON parsing in hooks)",
    });
  } else {
    checks.push({
      name: "jq",
      status: "warn",
      message: "jq not installed (optional, hooks will use grep fallback)",
    });
  }

  // Check 13: Windows platform detection
  if (isNativeWindows()) {
    checks.push({
      name: "Platform",
      status: "warn",
      message:
        "Running on native Windows - WSL recommended for full functionality (hooks, scripts)",
    });
  } else if (isWSL()) {
    checks.push({
      name: "Platform",
      status: "pass",
      message: "Running in WSL - full functionality available",
    });
  }
  // On macOS/Linux, don't add a platform check (not relevant)

  // Check 12: Optional MCP servers
  const mcpStatus = checkOptionalMcpServers();
  const configuredMcps = OPTIONAL_MCP_SERVERS.filter(
    (s) => mcpStatus[s.name],
  ).map((s) => s.name);
  const missingMcps = OPTIONAL_MCP_SERVERS.filter((s) => !mcpStatus[s.name]);

  if (configuredMcps.length === OPTIONAL_MCP_SERVERS.length) {
    checks.push({
      name: "MCP Servers",
      status: "pass",
      message: `All optional MCPs configured (${configuredMcps.join(", ")})`,
    });
  } else if (configuredMcps.length > 0) {
    checks.push({
      name: "MCP Servers",
      status: "pass",
      message: `Some MCPs configured: ${configuredMcps.join(", ")}`,
    });
    for (const mcp of missingMcps) {
      checks.push({
        name: `MCP: ${mcp.name}`,
        status: "warn",
        message: `Not configured (optional, enhances ${mcp.skills.join(", ")})`,
      });
    }
  } else {
    checks.push({
      name: "MCP Servers",
      status: "warn",
      message:
        "No optional MCPs configured (Sequant works without them, but they enhance functionality)",
    });
  }

  // Check: MCP availability for headless mode (sequant run)
  const mcpServersConfig = getMcpServersConfig();
  if (mcpServersConfig) {
    const serverCount = Object.keys(mcpServersConfig).length;
    checks.push({
      name: "MCP Servers (headless)",
      status: "pass",
      message: `Available for sequant run (${serverCount} server${serverCount !== 1 ? "s" : ""} configured)`,
    });
  } else {
    checks.push({
      name: "MCP Servers (headless)",
      status: "warn",
      message:
        "Not available for sequant run (no Claude Desktop config found or empty mcpServers)",
    });
  }

  // Check: Closed issue verification (only if gh available, authenticated, and not skipped)
  if (!options.skipIssueCheck && ghAvailable && ghAuthenticated && gitExists) {
    const missingCommitIssues = checkClosedIssues();
    if (missingCommitIssues.length === 0) {
      checks.push({
        name: "Closed Issues",
        status: "pass",
        message: "All recently closed issues have commits in main",
      });
    } else {
      // Add a warning for each issue missing commits
      for (const issue of missingCommitIssues) {
        checks.push({
          name: `Issue #${issue.number}`,
          status: "warn",
          message: `Closed but no commit found in main: "${issue.title}"`,
        });
      }
    }
  }

  // Display results with status icons
  let passCount = 0;
  let warnCount = 0;
  let failCount = 0;

  for (const check of checks) {
    const statusType =
      check.status === "pass"
        ? "success"
        : check.status === "warn"
          ? "warning"
          : "error";
    const color =
      check.status === "pass"
        ? colors.success
        : check.status === "warn"
          ? colors.warning
          : colors.error;

    console.log(
      `  ${ui.statusIcon(statusType as "success" | "warning" | "error")} ${chalk.bold(check.name)}: ${color(check.message)}`,
    );

    if (check.status === "pass") passCount++;
    else if (check.status === "warn") warnCount++;
    else failCount++;
  }

  // Summary with boxed output
  const totalChecks = passCount + warnCount + failCount;
  let summaryTitle: string;
  let summaryMessage: string;

  if (failCount > 0) {
    summaryTitle = `${failCount} check${failCount > 1 ? "s" : ""} failed`;
    summaryMessage = `Passed: ${passCount}/${totalChecks}\nWarnings: ${warnCount}\nFailed: ${failCount}\n\nRun \`sequant init\` to fix issues.`;
    console.log("\n" + ui.errorBox(summaryTitle, summaryMessage));
    process.exit(1);
  } else if (warnCount > 0) {
    summaryTitle = `All checks passed (${warnCount} warning${warnCount > 1 ? "s" : ""})`;
    summaryMessage = `Passed: ${passCount}/${totalChecks}\nWarnings: ${warnCount}\n\nSequant should work correctly.`;
    console.log("\n" + ui.warningBox(summaryTitle, summaryMessage));
  } else {
    summaryTitle = `All ${totalChecks} checks passed!`;
    summaryMessage = `Your Sequant installation is healthy.`;
    console.log("\n" + ui.successBox(summaryTitle, summaryMessage));
  }
}

#!/usr/bin/env node
/**
 * Sequant CLI - Quantize your development workflow
 *
 * Sequential AI phases with quality gates for any codebase.
 */

import { Command } from "commander";
import chalk from "chalk";
import { fileURLToPath } from "url";
import { dirname, resolve } from "path";
import { readFileSync } from "fs";
import { initCommand } from "../src/commands/init.js";
import { isLocalNodeModulesInstall } from "../src/lib/version-check.js";
import { configureUI, banner } from "../src/lib/cli-ui.js";
import { isCI, isStdoutTTY } from "../src/lib/tty.js";

// Read version from package.json dynamically
// Works from both source (bin/) and compiled (dist/bin/) locations
function getVersion(): string {
  const __dirname = dirname(fileURLToPath(import.meta.url));
  let dir = __dirname;
  while (dir !== dirname(dir)) {
    const candidate = resolve(dir, "package.json");
    try {
      const content = readFileSync(candidate, "utf-8");
      const pkg = JSON.parse(content);
      if (pkg.name === "sequant") {
        return pkg.version;
      }
    } catch {
      // Not found, continue searching
    }
    dir = dirname(dir);
  }
  return "0.0.0"; // Fallback
}
const version = getVersion();
import { updateCommand } from "../src/commands/update.js";
import { doctorCommand } from "../src/commands/doctor.js";
import { statusCommand } from "../src/commands/status.js";
import { runCommand } from "../src/commands/run.js";
import { logsCommand } from "../src/commands/logs.js";
import { statsCommand } from "../src/commands/stats.js";
import { dashboardCommand } from "../src/commands/dashboard.js";
import {
  stateInitCommand,
  stateRebuildCommand,
  stateCleanCommand,
} from "../src/commands/state.js";
import { syncCommand, areSkillsOutdated } from "../src/commands/sync.js";
import { mergeCommand } from "../src/commands/merge.js";
import { conventionsCommand } from "../src/commands/conventions.js";
import { getManifest } from "../src/lib/manifest.js";

const program = new Command();

// Handle --no-color before parsing
if (process.argv.includes("--no-color")) {
  process.env.FORCE_COLOR = "0";
}

// Configure UI early based on environment and flags
configureUI({
  noColor: process.argv.includes("--no-color") || !!process.env.NO_COLOR,
  jsonMode: process.argv.includes("--json"),
  verbose: process.argv.includes("--verbose") || process.argv.includes("-v"),
  isTTY: isStdoutTTY(),
  isCI: isCI(),
  minimal: process.env.SEQUANT_MINIMAL === "1",
});

// Warn if running from local node_modules (not npx cache or global)
// This helps users who accidentally have a stale local install
if (!process.argv.includes("--quiet") && isLocalNodeModulesInstall()) {
  console.warn(
    chalk.yellow(
      "⚠️  Running sequant from local node_modules\n" +
        "   For latest version: npx sequant@latest\n" +
        "   To remove local: npm uninstall sequant\n",
    ),
  );
}

program
  .name("sequant")
  .description(
    "Quantize your development workflow - Sequential AI phases with quality gates",
  )
  .version(version)
  .option("--no-color", "Disable colored output");

program
  .command("init")
  .description("Initialize Sequant in your project")
  .option("-s, --stack <stack>", "Specify stack (nextjs, rust, python, go)")
  .option("-y, --yes", "Skip confirmation prompts")
  .option("-f, --force", "Overwrite existing configuration")
  .option(
    "-i, --interactive",
    "Force interactive mode even in non-TTY environment",
  )
  .option("--skip-setup", "Skip the dependency setup wizard")
  .option(
    "--no-symlinks",
    "Use copies instead of symlinks for scripts/dev/ files",
  )
  .option("--no-agents-md", "Skip AGENTS.md generation")
  .action(initCommand);

program
  .command("update")
  .description("Update templates from the Sequant package")
  .option("-d, --dry-run", "Show what would be updated without making changes")
  .option("-f, --force", "Overwrite local modifications")
  .action(updateCommand);

program
  .command("sync")
  .description(
    "Sync skills and templates from the Sequant package (non-interactive)",
  )
  .option("-f, --force", "Sync even if versions match")
  .option("-q, --quiet", "Suppress output")
  .action(syncCommand);

program
  .command("doctor")
  .description("Check your Sequant installation for issues")
  .option("--skip-issue-check", "Skip closed-issue verification check")
  .action(doctorCommand);

program
  .command("status")
  .description("Show Sequant version, configuration, and workflow state")
  .argument("[issue]", "Issue number to show details for", parseInt)
  .option("--issues", "Show all tracked issues")
  .option("--json", "Output as JSON")
  .option("--rebuild", "Rebuild state from run logs")
  .option("--cleanup", "Clean up stale/orphaned entries")
  .option("--dry-run", "Preview cleanup without changes")
  .option("--max-age <days>", "Remove entries older than N days", parseInt)
  .option("--all", "Remove all orphaned entries (merged and abandoned)")
  .action((issue, options) => {
    // Support positional arg: `sequant status 42` → --issue 42
    if (issue) {
      options.issue = issue;
    }
    return statusCommand(options);
  });

program
  .command("run")
  .description("Execute workflow for GitHub issues using Claude Agent SDK")
  .argument("[issues...]", "Issue numbers to process")
  .option("--phases <list>", "Phases to run (default: spec,exec,qa)")
  .option("--sequential", "Stop on first issue failure (default: continue)")
  .option("-d, --dry-run", "Preview without execution")
  .option("-v, --verbose", "Verbose output with streaming")
  .option("--timeout <seconds>", "Timeout per phase in seconds", parseInt)
  .option("--log-json", "Enable structured JSON logging (default: true)")
  .option("--no-log", "Disable JSON logging for this run")
  .option("--log-path <path>", "Custom log directory path")
  .option("-q, --quality-loop", "Enable quality loop with auto-retry")
  .option(
    "--max-iterations <n>",
    "Max iterations for quality loop (default: 3)",
    parseInt,
  )
  .option(
    "--batch <issues>",
    'Group of issues to run together (e.g., --batch "1 2" --batch "3")',
    (value: string, prev: string[]) => prev.concat([value]),
    [],
  )
  .option("--smart-tests", "Enable smart test detection (default)")
  .option("--no-smart-tests", "Disable smart test detection")
  .option("--testgen", "Run testgen phase after spec")
  .option("--quiet", "Suppress version warnings and non-essential output")
  .option(
    "--chain",
    "Chain issues: each branches from previous (implies --sequential)",
  )
  .option(
    "--qa-gate",
    "Wait for QA pass before starting next issue in chain (requires --chain)",
  )
  .option(
    "--base <branch>",
    "Base branch for worktree creation (default: main or settings.run.defaultBase)",
  )
  .option("--no-mcp", "Disable MCP server injection in headless mode")
  .option(
    "--no-retry",
    "Disable automatic retry with MCP fallback (useful for debugging)",
  )
  .option(
    "--resume",
    "Resume from last completed phase (reads phase markers from GitHub)",
  )
  .option(
    "--no-rebase",
    "Skip pre-PR rebase onto origin/main (use when you want to handle rebasing manually)",
  )
  .option(
    "--no-pr",
    "Skip PR creation after successful QA (manual PR workflow)",
  )
  .option(
    "-f, --force",
    "Force re-execution of completed issues (bypass pre-flight state guard)",
  )
  .option("--reflect", "Analyze run results and suggest improvements")
  .option(
    "--agent <name>",
    'Agent driver for phase execution (default: "claude-code")',
  )
  .action(runCommand);

program
  .command("merge")
  .description(
    "Batch-level integration QA — verify feature branches before merging",
  )
  .argument(
    "[issues...]",
    "Issue numbers to check (auto-detects from most recent run if omitted)",
  )
  .option("--check", "Run Phase 1 deterministic checks (default)")
  .option("--scan", "Run Phase 1 + Phase 2 residual pattern detection")
  .option("--review", "Run Phase 1 + 2 + 3 AI briefing")
  .option("--all", "Run all phases")
  .option("--post", "Post report to GitHub as PR comments")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .action(mergeCommand);

program
  .command("conventions")
  .description("View and manage codebase conventions")
  .option("--detect", "Re-run convention detection")
  .option("--reset", "Clear detected conventions (keep manual)")
  .option("--format <format>", "Output format (agents-md for AGENTS.md format)")
  .action(conventionsCommand);

program
  .command("logs")
  .description("View and analyze workflow run logs")
  .option("-p, --path <path>", "Custom log directory path")
  .option("-n, --last <n>", "Show last N runs", parseInt)
  .option("--json", "Output as JSON")
  .option("-i, --issue <number>", "Filter by issue number", parseInt)
  .option("--failed", "Show only failed runs")
  .option("--rotate", "Rotate logs (delete oldest to meet thresholds)")
  .option("-d, --dry-run", "Show what would be rotated without deleting")
  .action(logsCommand);

program
  .command("stats")
  .description("Show aggregate statistics for workflow runs")
  .option("-p, --path <path>", "Custom log directory path")
  .option("--csv", "Output as CSV")
  .option("--json", "Output as JSON")
  .action(statsCommand);

program
  .command("dashboard")
  .description("Start visual workflow dashboard in browser")
  .option("-p, --port <port>", "Port to run server on", parseInt)
  .option("--no-open", "Don't automatically open browser")
  .option("-v, --verbose", "Enable verbose logging")
  .action(dashboardCommand);

// State management command with subcommands
const stateCmd = program
  .command("state")
  .description("Manage workflow state for worktrees");

stateCmd
  .command("init")
  .description("Populate state for untracked worktrees")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .action(stateInitCommand);

stateCmd
  .command("rebuild")
  .description("Recreate state from logs and worktrees")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .option("-f, --force", "Force rebuild without confirmation")
  .action(stateRebuildCommand);

stateCmd
  .command("clean")
  .description("Remove entries for deleted worktrees")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .option("-d, --dry-run", "Preview cleanup without changes")
  .option("--max-age <days>", "Remove entries older than N days", parseInt)
  .option("--all", "Remove all orphaned entries (merged and abandoned)")
  .action(stateCleanCommand);

// Auto-sync skills after npm upgrade (version mismatch detection)
// Only triggers when skills were previously synced (has .sequant-version marker).
// Projects that manage skills manually (no marker) are not affected.
program.hook("preAction", async (thisCommand) => {
  const cmd = thisCommand.name();
  if (cmd === "init" || cmd === "sync") return;

  const manifest = await getManifest();
  if (!manifest) return;

  const { outdated, currentVersion } = await areSkillsOutdated();
  if (outdated && currentVersion !== null) {
    await syncCommand({ quiet: true });
  }
});

// Parse and execute
program.parse();

// Show help if no command provided
if (!process.argv.slice(2).length) {
  console.log(banner());
  program.help();
}

